mapper.select:
select 

from 

where 1=1

	and USERCOUPON_ID = #{USERCOUPON_ID}


	and COUPON_ID = #{COUPON_ID}


	and USER_ID = #{USER_ID}

select a.USER_ID, a.COUPON_ID, a.COUPON_STATE, a.APPLY_TIME, a.USE_TIME, a.MEMO, a.USERCOUPON_ID, b.USERNAME as USER_NAME, c.COUPON_NAME, c.COUPON_PRICE, c.USE_PRICE, c.STARTTIME, c.ENDTIME from SHOP_USERCOUPON a,SYS_APP_USER b,SHOP_COUPON c where a.USER_ID = b.USER_ID and a.COUPON_ID = c.COUPON_ID
and ( c.COUPON_NAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or c.CHANGE_CODE LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') )
and a.APPLY_TIME >= #{pd.lastStart}
and a.APPLY_TIME <= #{pd.lastEnd}
and a.USER_ID = #{pd.USER_ID}
and a.COUPON_STATE=#{pd.COUPON_STATE} and c.ENDTIME >= sysdate()
and a.COUPON_STATE=#{pd.COUPON_STATE}
and c.ENDTIME < sysdate() and a.COUPON_STATE='0'
and c.STARTTIME <=#{pd.NOWTIME} and c.ENDTIME >= #{pd.NOWTIME}
and c.USE_PRICE <=#{pd.USE_PRICE}
order by c.COUPON_PRICE desc
